#include "ai_factory/cuda/hull_white/zero_coupon_bonds.cuh"
#include "ai_factory/common/fixed_income/nelson_siegel.hpp"
#include "ai_factory/cuda/common/runtime.cuh"
namespace ai_factory::cuda {namespace{struct ZeroCouponWorkspaceTag{};__global__ void kernel(const HullWhiteZeroCouponBondRow* rows,std::size_t count,MonteCarloOutput* outputs){const std::size_t i=static_cast<std::size_t>(blockIdx.x)*blockDim.x+threadIdx.x;if(i>=count)return;const auto row=rows[i];outputs[i]={row.product.notional*fixed_income::nelson_siegel_discount(row.product.maturity,row.beta0,row.beta1,row.beta2,row.tau),0.0};}}
void price_hull_white_zero_coupon_bond_cuda(const HullWhiteZeroCouponBondRow*host,std::size_t count,MonteCarloOutput*out,CudaTiming*timing){auto&w=detail::reusable_cuda_workspace<ZeroCouponWorkspaceTag,2>();auto*r=w.buffer<HullWhiteZeroCouponBondRow>(0,count,"zero coupon rows");auto*o=w.buffer<MonteCarloOutput>(1,count,"zero coupon outputs");detail::check_cuda(cudaMemcpy(r,host,count*sizeof(*host),cudaMemcpyHostToDevice),"copy zero coupon rows");auto a=w.start_event(),b=w.stop_event();detail::check_cuda(cudaEventRecord(a),"event start");kernel<<<static_cast<unsigned>((count+255U)/256U),256>>>(r,count,o);detail::check_cuda(cudaGetLastError(),"Hull-White zero coupon kernel");detail::check_cuda(cudaEventRecord(b),"event stop");detail::check_cuda(cudaEventSynchronize(b),"event sync");float ms=0;detail::check_cuda(cudaEventElapsedTime(&ms,a,b),"event elapsed");detail::check_cuda(cudaMemcpy(out,o,count*sizeof(*out),cudaMemcpyDeviceToHost),"copy zero coupon outputs");if(timing){timing->simulation_ms=ms;timing->total_ms=ms;}}
}
